var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"쓰러뜨렸어......","JPN":"倒した……","ENG":"I won...","TWN":"打敗了……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니, 방금 봤어요......?","JPN":"リタお姉ちゃん、今の見ました……？","ENG":"Did you just see that, Rita?","TWN":"麗塔姐姐，你看到了嗎……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저, 저 혼자서 침식체를 해치웠어요. 잘했죠......?","JPN":"わ、私が一人で侵食体を倒しました。えらいでしょう……？","ENG":"I-I defeated a C.O. all by myself. I did a good job, right?","TWN":"我、我自己打敗了侵蝕體。我做得好吧……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대장님이 갑자기 침식체로 변해서...... 무서웠지만 언니를 지키려고 열심히 싸웠다고요.","JPN":"隊長が急に侵食体になって……すごく怖かったけどお姉ちゃんを守ろうと一生懸命に戦ったんです。","ENG":"The Captain suddenly turned into a C.O.... It was scary, but I fought so hard to protect you.","TWN":"隊長突然變成侵蝕體了……我雖然很害怕，但為了保護姐姐，我有用盡了全力。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저...... 잘한 거 맞죠? 그런 거죠?","JPN":"だから……これでよかったんですね？","ENG":"I... did a good job, right? Right?","TWN":"我……我做得很好吧？對吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......흑.","JPN":"……ぐすん。","ENG":"*Sob*","TWN":"……呃。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"죄송해요...... 제가 떼만 안 썼어도 여기 오지 않았을 텐데...... 죄송해요...... 정말 죄송해요......","JPN":"ごめんなさい……私がわがままを言わなければこんな所まで来ることなかったのに……ごめんなさい……本当にごめんなさい……","ENG":"I'm sorry... We wouldn't be here if I hadn't insisted... I'm sorry... I'm so sorry...","TWN":"對不起……如果不是我耍賴就不會來這裡了……對不起……真的對不起……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"흐흑...... 윽......","JPN":"うう……ううっ……","ENG":"*Sniffle...* Ngh...","TWN":"呃……呃……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"눈물, 흑...... 달아나, 흐윽...... 흑......","JPN":"涙の、ぐすん……飛んでけ、ううっ……うっ……","ENG":"Go away... Tear fairy... ngh... *Sob*","TWN":"眼淚，嗚……快給我通通飛走，嗚……嗚嗚……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>데이터 백업 상태 양호. 시스템 재가동.</color>","JPN":"<color=#ffd34c>データバックアップ状態良好。システム再稼働。</color>","ENG":"<color=#ffd34c>Backup data integrity verified. Rebooting system.</color>","TWN":"<color=#ffd34c>資料備份狀態良好。系統重新開機。</color>"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"시작형 전술통제용 강인공지능, 호라이즌. 기동 개시.","JPN":"試作型戦術統制用の強人工知能、ホライズン。起動開始。","ENG":"Prototype tactical control artificial general intelligence, HORIZON. Activating system.","TWN":"原型戰略操作高度人工智慧，地平線。開始啟動。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UNIT_AIR_DRONE_START"},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대표님......?","JPN":"代表……？","ENG":"Boss?","TWN":"BOSS……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대표님! 그동안 어디 계셨던 거예요! 얼마나 걱정했는데요!","JPN":"代表！　今までどこにいたんですか！　どれだけ心配したかわかってますか！？","ENG":"Boss! Where have you been?! I was worried sick about you!","TWN":"BOSS！您去哪裡了！您都不知道我有多擔心！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"미안합니다. 대시.","JPN":"ごめんなさい、ダッシュ。","ENG":"I'm sorry, Dash.","TWN":"對不起，黛西。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"지근거리에서 4종 이상의 고밀도 침식파에 노출되어 일시적으로 기동이 중지됐습니다.","JPN":"至近距離で第4種以上の高密度侵食波にさらされて、一時的に起動が停止していました。","ENG":"I was temporarily shut down due to exposure to a potent Corruption Ray from a Category 4.","TWN":"因為碰上近距離4類以上高密度侵蝕波中，暫時停止運行了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"4종 이상......이요?","JPN":"第4種以上……ですか？","ENG":"A Category 4?","TWN":"4類以上……嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"네. 침식파의 발원지는 탐사대 한복판이었습니다. 이상한 일이죠.","JPN":"はい。侵食波の発源地は探査隊の中心でした。おかしなことです。","ENG":"Yes. The Corruption Ray seems to have originated from the heart of the expedition base camp. It's quite odd.","TWN":"是的。侵蝕波的來源地位於探索隊的中心。這很奇怪。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"마지막에 측정된 침식파의 파형으로 계산한 방출 지점은......","JPN":"最後に測定された侵食波の波形で計算した放出地点は……","ENG":"Based on the trajectory of the final burst of the rays, the exact point of origin is...","TWN":"以最後測量到的侵蝕波波形去計算後，得出的釋放點是……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......흠.","JPN":"……ふむ。","ENG":"Hmm.","TWN":"……呃。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"당장 우려해야 될 위협 요소는 아니니 보류해 두죠.","JPN":"今すぐ憂慮すべき懸念要素ではないので、保留にしておきましょう。","ENG":"Perhaps we can put this matter aside for now as it does not present an immediate threat.","TWN":"目前判斷這不會構成威脅，我先保留吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그보다 왜 울고 있었습니까. 주인한테 버림 받고 비 맞는 강아지처럼.","JPN":"それよりなぜ泣いていたのですか。主人に捨てられて雨に濡れた迷子犬みたいです。","ENG":"By the way, why were you crying? You resembled an abandoned puppy whimpering in the rain.","TWN":"話說回來，你為什麼哭呢？像是被主人拋棄獨自在外面淋雨的小狗一樣。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그게......","JPN":"それが……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그렇군요. 인간이 침식체로 변이하는 광경을 직접 목격하면 충격 받는 건 당연합니다.","JPN":"そうでしたか。人間が侵食体に変異する光景を目撃して衝撃を受けるのは当然のことです。","ENG":"I see. It is natural for humans to be traumatized from witnessing a fellow human transform into a C.O.","TWN":"原來如此。親眼看到人類變異為侵蝕體的樣子，必然會受到衝擊的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대표님은...... 전부 알고 계셨어요?","JPN":"代表は……知っていたんですか？","ENG":"You mean... you knew about this before?","TWN":"BOSS……您都知道？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"대중매체에서 묘사를 금지하고 있을 뿐, 관계자들 사이에서는 공공연한 사실이죠.","JPN":"マスメディアでの発表を禁止しているだけで、関係者の間では公然の事実です。","ENG":"It's common knowledge in the industry, despite the censorship against its depiction in mass media.","TWN":"只是禁止大眾媒體報導而已，但相關人士都知道這個事實。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"너무 상심하지 마십시오. 대시는 용병 대장이 다른 사람을 해치지 않게 막아 준 겁니다.","JPN":"あまり落ち込まないでください。ダッシュは傭兵隊長が他の人を傷つけてしまう前に止めてあげたのです。","ENG":"You don't need to feel so down. You stopped the mercenary captain from hurting anyone else.","TWN":"別太傷心了。黛西你是阻止傭兵隊長傷害其他人。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......고마워요, 대표님. 그렇게 말해 주셔서.","JPN":"……ありがとうございます、代表。そう言ってくれて。","ENG":"Thank you... Boss. That's very kind of you.","TWN":"……謝謝，BOSS。謝謝你這麼說。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"실패로 낙담한 직원을 위로해 주는 것도 대표가 할 일입니다.","JPN":"失敗して落胆している社員を慰めるのも代表としての仕事です。","ENG":"A responsible employer knows when to encourage an employee disheartened by failure.","TWN":"安慰因失敗而沮喪的職員也是老闆應該做的事情。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그보다 이런 일을 예상했다면 무리해서라도 전투용 프레임을 투입했을 텐데, 아쉽군요.","JPN":"それより、こうなると予想できたなら無理をしてでも戦闘用フレームを投入しておけばよかったですね。","ENG":"If I had expected this to happen, I would have come in my combat frame. Too bad.","TWN":"早知道會發生這樣的事情，即使勉強也應該投入一些戰鬥飛行器的，真可惜。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타가 또 자책하겠어요. 당신에게 상처를 입혔다고.","JPN":"リタがまた自分を責めてしまいそうです。あなたを傷つけてしまったと。","ENG":"Rita will blame herself again. For getting you hurt.","TWN":"麗塔這下子又會自責讓你受傷了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네?","JPN":"どういう意味ですか？","ENG":"Sorry?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"아무것도 아닙니다.","JPN":"何でもありません。","ENG":"It's nothing.","TWN":"沒什麼。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"주위에 아직 3종급의 침식파 반응이 감지되고 있습니다. 여긴 안전하지 않아요.","JPN":"周辺に第3種レベルの侵食波反応を感知しています。ここは安全ではありませんね。","ENG":"I can still detect Corruption Rays equivalent to those of Category 3 C.O.s in the vicinity. It's not safe here.","TWN":"現在周圍依舊可以感知到3類侵蝕波。這裡不安全。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"3종이면...... 함선을 격추시켰던 그 침식체들일까요?","JPN":"第3種ということは……艦船を撃墜したあの侵食体でしょうか？","ENG":"Category 3... Could it be those C.O.s that took down the ships?","TWN":"3類的話……是擊落艦船的那些侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"확실하지는 않습니다만, 예약 없이 만나기 싫은 손님이란 점은 마찬가지군요.","JPN":"確かではありませんが、アポなしで来る客のようなものですし、遭遇するのは避けたいですね。","ENG":"It's unclear, but they're definitely not the sort I'd want to face.","TWN":"雖然不確定，應該是那群不速之客。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"가죠, 대시. 먼저 몸을 피할 수 있는 곳부터 찾아야 합니다.","JPN":"行きましょう、ダッシュ。まずは避難できる場所を探さなければなりません。","ENG":"Let's go, Dash. We must take shelter first.","TWN":"走吧，黛西。要先找到安全的地方藏身。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};